import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const ReportScreen = () => {
    const [complaints, setComplaints] = useState([]);
    const [filters, setFilters] = useState({
        department: '',
        programme: '',
        complaintType: '',
        status: '',
        assignee: ''
    });
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(false);
    const [showReport, setShowReport] = useState(false);

    const typeOptions = ['PC Hardware', 'PC Software', 'Application Issues', 'Network', 'Electronics', 'Plumbing'];
    const statusOptions = ['Pending', 'Assigned', 'In-Progress', 'On-Hold', 'Completed'];

    useEffect(() => {
        fetchDepartments();
        fetchUsers();
    }, []);

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            console.error('Error fetching departments:', err);
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            console.error('Error fetching programmes:', err);
        }
    };

    const fetchUsers = async () => {
        try {
            const { data } = await API.get('/master/users');
            const staff = data.filter(u => ['Plumber', 'Electrician', 'Networking Staff', 'Software Developer'].includes(u.role));
            setUsers(staff);
        } catch (err) {
            console.error('Error fetching users:', err);
        }
    };

    const handleGenerateReport = async () => {
        setLoading(true);
        try {
            const { data } = await API.get('/complaints');
            let filtered = data;

            if (filters.department) {
                filtered = filtered.filter(c => c.department?._id === filters.department);
            }
            if (filters.programme) {
                filtered = filtered.filter(c => c.programme?._id === filters.programme);
            }
            if (filters.complaintType) {
                filtered = filtered.filter(c => c.complaintType === filters.complaintType);
            }
            if (filters.status) {
                filtered = filtered.filter(c => c.status === filters.status);
            }
            if (filters.assignee) {
                filtered = filtered.filter(c => c.assignedTo?._id === filters.assignee);
            }

            setComplaints(filtered);
            setShowReport(true);
        } catch (err) {
            console.error('Error generating report:', err);
        } finally {
            setLoading(false);
        }
    };

    const handlePrint = () => {
        window.print();
    };

    const handleExportCSV = () => {
        if (complaints.length === 0) {
            alert('No data to export');
            return;
        }

        const headers = ['Block', 'Room', 'Type', 'Status', 'Remarks', 'Raised By', 'Assigned To', 'Created Date'];
        const rows = complaints.map(c => [
            c.blockName,
            c.roomNumber,
            c.complaintType,
            c.status,
            c.complaintRemarks,
            c.user?.userName || '',
            c.assignedTo?.userName || 'Unassigned',
            new Date(c.createdAt).toLocaleDateString()
        ]);

        let csv = headers.join(',') + '\n';
        rows.forEach(row => {
            csv += row.map(val => `"${val}"`).join(',') + '\n';
        });

        const blob = new Blob([csv], { type: 'text/csv' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'complaints_report.csv';
        a.click();
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFilters({...filters, department: deptId, programme: ''});
        if (deptId) {
            fetchProgrammes(deptId);
        }
    };

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>📊 Complaint Reports</h1>
                    <p style={styles.subtitle}>Generate and analyze detailed complaint reports</p>
                </div>

                {!showReport ? (
                    <div style={styles.filterCard}>
                        <h3 style={styles.filterTitle}>🔍 Report Filters</h3>
                        <div style={styles.filterGrid}>
                            <div style={styles.filterGroup}>
                                <label style={styles.label}>🏢 Department</label>
                                <select 
                                    value={filters.department}
                                    onChange={handleDepartmentChange}
                                    style={styles.input}
                                >
                                    <option value="">All Departments</option>
                                    {departments.map(d => <option key={d._id} value={d._id}>{d.deptName}</option>)}
                                </select>
                            </div>

                            <div style={styles.filterGroup}>
                                <label style={styles.label}>📚 Programme</label>
                                <select 
                                    value={filters.programme}
                                    onChange={e => setFilters({...filters, programme: e.target.value})}
                                    style={styles.input}
                                >
                                    <option value="">All Programmes</option>
                                    {programmes.map(p => <option key={p._id} value={p._id}>{p.programmeName}</option>)}
                                </select>
                            </div>

                            <div style={styles.filterGroup}>
                                <label style={styles.label}>🔧 Complaint Type</label>
                                <select 
                                    value={filters.complaintType}
                                    onChange={e => setFilters({...filters, complaintType: e.target.value})}
                                    style={styles.input}
                                >
                                    <option value="">All Types</option>
                                    {typeOptions.map(t => <option key={t} value={t}>{t}</option>)}
                                </select>
                            </div>

                            <div style={styles.filterGroup}>
                                <label style={styles.label}>⏱️ Status</label>
                                <select 
                                    value={filters.status}
                                    onChange={e => setFilters({...filters, status: e.target.value})}
                                    style={styles.input}
                                >
                                    <option value="">All Statuses</option>
                                    {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                                </select>
                            </div>

                            <div style={styles.filterGroup}>
                                <label style={styles.label}>👤 Assignee (Staff)</label>
                                <select 
                                    value={filters.assignee}
                                    onChange={e => setFilters({...filters, assignee: e.target.value})}
                                    style={styles.input}
                                >
                                    <option value="">All Staff</option>
                                    {users.map(u => <option key={u._id} value={u._id}>{u.userName}</option>)}
                                </select>
                            </div>
                        </div>

                        <button 
                            onClick={handleGenerateReport}
                            disabled={loading}
                            style={{...styles.generateButton, opacity: loading ? 0.6 : 1}}
                        >
                            {loading ? '⏳ Generating Report...' : '📈 Generate Report'}
                        </button>
                    </div>
                ) : (
                    <div>
                        <div style={styles.reportActions}>
                            <button 
                                onClick={() => setShowReport(false)}
                                style={styles.actionButton}
                            >
                                ← Edit Filters
                            </button>
                            <button 
                                onClick={handlePrint}
                                style={{...styles.actionButton, background: 'linear-gradient(135deg, #3b82f6, #2563eb)'}}
                            >
                                🖨️ Print
                            </button>
                            <button 
                                onClick={handleExportCSV}
                                style={{...styles.actionButton, background: 'linear-gradient(135deg, #10b981, #059669)'}}
                            >
                                📥 Export CSV
                            </button>
                        </div>

                        <div style={styles.reportContainer}>
                            <div style={styles.reportHeader}>
                                <h3 style={styles.reportTitle}>📋 Report Results</h3>
                                <span style={styles.recordCount}>{complaints.length} records found</span>
                            </div>
                            
                            {complaints.length === 0 ? (
                                <div style={styles.noResults}>
                                    <p>📭 No complaints found matching the criteria</p>
                                </div>
                            ) : (
                                <div style={styles.tableWrapper}>
                                    <table style={styles.table}>
                                        <thead>
                                            <tr style={styles.tableHeaderRow}>
                                                <th style={{...styles.tableHeader, width: '10%'}}>Block</th>
                                                <th style={{...styles.tableHeader, width: '8%'}}>Room</th>
                                                <th style={{...styles.tableHeader, width: '15%'}}>Type</th>
                                                <th style={{...styles.tableHeader, width: '10%'}}>Status</th>
                                                <th style={{...styles.tableHeader, width: '20%'}}>Remarks</th>
                                                <th style={{...styles.tableHeader, width: '12%'}}>Raised By</th>
                                                <th style={{...styles.tableHeader, width: '12%'}}>Assigned To</th>
                                                <th style={{...styles.tableHeader, width: '13%'}}>Date</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {complaints.map((c, idx) => (
                                                <tr key={c._id} style={idx % 2 === 0 ? styles.tableRowEven : styles.tableRowOdd}>
                                                    <td style={styles.tableCell}>{c.blockName}</td>
                                                    <td style={{...styles.tableCell, textAlign: 'center'}}>
                                                        <span style={styles.badge}>{c.roomNumber}</span>
                                                    </td>
                                                    <td style={styles.tableCell}>{c.complaintType}</td>
                                                    <td style={styles.tableCell}>
                                                        <span style={{...styles.statusBadge, background: getStatusGradient(c.status)}}>
                                                            {c.status}
                                                        </span>
                                                    </td>
                                                    <td style={{...styles.tableCell, maxWidth: '150px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap'}}>{c.complaintRemarks}</td>
                                                    <td style={styles.tableCell}>{c.user?.userName}</td>
                                                    <td style={styles.tableCell}>{c.assignedTo?.userName || '❌ Unassigned'}</td>
                                                    <td style={{...styles.tableCell, fontSize: '0.85rem'}}>{new Date(c.createdAt).toLocaleDateString()}</td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

const getStatusGradient = (status) => {
    const colors = {
        'Pending': 'linear-gradient(135deg, #f59e0b, #f97316)',
        'Assigned': 'linear-gradient(135deg, #8b5cf6, #a78bfa)',
        'In-Progress': 'linear-gradient(135deg, #3b82f6, #60a5fa)',
        'On-Hold': 'linear-gradient(135deg, #ef4444, #f87171)',
        'Completed': 'linear-gradient(135deg, #10b981, #34d399)'
    };
    return colors[status] || 'linear-gradient(135deg, #6b7280, #9ca3af)';
};

const styles = {
    pageWrapper: { minHeight: '100vh', background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)', color: '#e0e7ff', fontFamily: "'Poppins', sans-serif" },
    contentArea: { maxWidth: '1600px', margin: '0 auto', padding: '40px 30px' },
    headerSection: { marginBottom: '40px' },
    mainTitle: { fontSize: '2.2rem', fontWeight: 800, background: 'linear-gradient(135deg, #38bdf8, #818cf8)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text', marginBottom: '10px' },
    subtitle: { fontSize: '1rem', color: '#94a3b8', fontWeight: 500 },
    
    filterCard: { background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))', backdropFilter: 'blur(15px)', border: '2px solid rgba(51, 65, 85, 0.3)', borderRadius: '16px', padding: '28px', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)' },
    filterTitle: { fontSize: '1.2rem', fontWeight: 700, color: '#e0e7ff', marginBottom: '24px' },
    filterGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '24px' },
    filterGroup: { display: 'flex', flexDirection: 'column' },
    label: { fontSize: '0.95rem', fontWeight: 600, color: '#cbd5e1', marginBottom: '8px', letterSpacing: '0.3px' },
    input: { padding: '12px 16px', background: 'rgba(20, 28, 45, 0.6)', border: '2px solid rgba(51, 65, 85, 0.4)', borderRadius: '12px', color: '#fff', fontSize: '0.95rem', fontFamily: "'Poppins', sans-serif", transition: 'all 0.3s ease', boxSizing: 'border-box', cursor: 'pointer' },
    generateButton: { width: '100%', padding: '14px 24px', background: 'linear-gradient(135deg, #38bdf8, #818cf8)', border: 'none', borderRadius: '12px', color: 'white', fontSize: '1rem', fontWeight: 700, cursor: 'pointer', transition: 'all 0.3s ease', fontFamily: "'Poppins', sans-serif", boxShadow: '0 10px 30px -8px rgba(56, 189, 248, 0.3)' },
    
    reportActions: { display: 'flex', gap: '12px', marginBottom: '24px', flexWrap: 'wrap' },
    actionButton: { padding: '12px 20px', background: 'linear-gradient(135deg, #6b7280, #4b5563)', border: 'none', borderRadius: '12px', color: 'white', fontSize: '0.95rem', fontWeight: 700, cursor: 'pointer', transition: 'all 0.3s ease', fontFamily: "'Poppins', sans-serif", boxShadow: '0 4px 15px rgba(0,0,0,0.2)' },
    
    reportContainer: { background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))', backdropFilter: 'blur(15px)', border: '2px solid rgba(51, 65, 85, 0.3)', borderRadius: '16px', padding: '28px', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)' },
    reportHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', paddingBottom: '16px', borderBottom: '2px solid rgba(51, 65, 85, 0.3)' },
    reportTitle: { fontSize: '1.3rem', fontWeight: 700, color: '#e0e7ff' },
    recordCount: { background: 'linear-gradient(135deg, #38bdf8, #818cf8)', padding: '6px 16px', borderRadius: '20px', fontSize: '0.85rem', fontWeight: 700, color: 'white' },
    noResults: { textAlign: 'center', padding: '60px 20px', color: '#94a3b8' },
    
    tableWrapper: { overflowX: 'auto' },
    table: { width: '100%', borderCollapse: 'collapse' },
    tableHeaderRow: { background: 'linear-gradient(135deg, rgba(56, 189, 248, 0.1), rgba(129, 140, 248, 0.1))' },
    tableHeader: { padding: '14px 12px', textAlign: 'left', color: '#e0e7ff', fontWeight: 700, fontSize: '0.85rem', borderBottom: '2px solid rgba(51, 65, 85, 0.3)', letterSpacing: '0.5px', textTransform: 'uppercase' },
    tableRowEven: { background: 'rgba(56, 189, 248, 0.05)' },
    tableRowOdd: { background: 'transparent' },
    tableCell: { padding: '12px 12px', borderBottom: '1px solid rgba(51, 65, 85, 0.2)', color: '#cbd5e1', fontSize: '0.9rem' },
    badge: { display: 'inline-block', background: 'linear-gradient(135deg, #ec4899, #f59e0b)', color: 'white', padding: '4px 10px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 700, textTransform: 'uppercase' },
    statusBadge: { display: 'inline-block', color: 'white', padding: '4px 10px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 700, textTransform: 'uppercase' },
};

export default ReportScreen;
